#   export S3_BUCKET_NAME="demo-bucket"             # optional, defaults to demo-bucket
#
# On Windows (PowerShell):
#   $env:AWS_ACCESS_KEY_ID="your-access-key-here"
#   $env:AWS_SECRET_ACCESS_KEY="your-secret-key-here"
#   $env:AWS_DEFAULT_REGION="us-east-1"
#   $env:S3_BUCKET_NAME="demo-bucket"
#
# Alternatively, you can create a .env file (DO NOT commit it to version control)
# and use python-dotenv to load it. Make sure .env is in your .gitignore.
# =============================================================================

def load_env_file():
    """Attempt to load a .env file if python-dotenv is available."""
    try:
        from dotenv import load_dotenv
        load_dotenv()
        print("[INFO] Loaded environment variables from .env file.")
    except ImportError:
        pass


def get_required_env(var_name, friendly_name=None):
    """Retrieve a required environment variable or exit with a helpful message."""
    value = os.environ.get(var_name)
    if not value:
        display_name = friendly_name or var_name
        print(f"[ERROR] Missing required environment variable: {var_name}")
        print(f"        Please set {var_name} with your {display_name} before running this script.")
        print()
        print(f"  Example (Linux/macOS): export {var_name}=\"your-value-here\"")
        print(f"  Example (Windows PS):  $env:{var_name}=\"your-value-here\"")
        sys.exit(1)
    return value


def list_s3_bucket_files(bucket_name, aws_access_key_id, aws_secret_access_key, region):
    """Connect to S3 and list all files in the specified bucket."""
    s3_client = boto3.client(
        "s3",
        aws_access_key_id=aws_access_key_id,
        aws_secret_access_key=aws_secret_access_key,
        region_name=region,
    )

    print(f"\n{'='*60}")
    print(f"  Listing files in S3 bucket: {bucket_name}")
    print(f"  Region: {region}")
    print(f"{'='*60}\n")

    try:
        paginator = s3_client.get_paginator("list_objects_v2")
        page_iterator = paginator.paginate(Bucket=bucket_name)

        file_count = 0
        total_size = 0

        for page in page_iterator:
            if "Contents" not in page:
                continue
            for obj in page["Contents"]:
                file_count += 1
                size_kb = obj["Size"] / 1024
                last_modified = obj["LastModified"].strftime("%Y-%m-%d %H:%M:%S")
                print(f"  {file_count:4d}. {obj['Key']}")
                print(f"        Size: {size_kb:,.2f} KB | Last Modified: {last_modified}")
                total_size += obj["Size"]

        print(f"\n{'='*60}")
        if file_count == 0:
            print("  No files found in the bucket.")
        else:
            total_size_mb = total_size / (1024 * 1024)
            print(f"  Total files: {file_count}")
            print(f"  Total size:  {total_size_mb:,.2f} MB")
        print(f"{'='*60}\n")

    except ClientError as e:
        error_code = e.response["Error"]["Code"]
        error_message = e.response["Error"]["Message"]
        print(f"[ERROR] AWS S3 error ({error_code}): {error_message}")
        sys.exit(1)
    except NoCredentialsError:
        print("[ERROR] AWS credentials are invalid or not properly configured.")
        sys.exit(1)


def main():
    # Try to load .env file if available
    load_env_file()

    # Load credentials from environment variables (NEVER hardcode them)
    aws_access_key_id = get_required_env("AWS_ACCESS_KEY_ID", "AWS Access Key ID")
    aws_secret_access_key = get_required_env("AWS_SECRET_ACCESS_KEY", "AWS Secret Access Key")
    region = os.environ.get("AWS_DEFAULT_REGION", "us-east-1")
    bucket_name = os.environ.get("S3_BUCKET_NAME", "demo-bucket")

    list_s3_bucket_files(bucket_name, aws_access_key_id, aws_secret_access_key, region)


if __name__ == "__main__":
    main()